      {/* Outfit recommendation overlay (from recommendation pipeline) */}
      {outfitData && outfits.length > 0 && (
        <div
          style={{
            position: "absolute",
            bottom: 0,
            left: 0,
            right: 0,
            zIndex: 15,
            pointerEvents: "none",
          }}
        >
          <OutfitsView
            greeting={outfitData.greeting}
            styleAnalysis={outfitData.style_analysis}
            outfits={outfits}
            activeIndex={outfitActiveIndex}
            onDotClick={setOutfitActiveIndex}
          />
        </div>
      )}

      {/* Voice indicator (bottom-left, session only) */}
      {sessionActive && (
        <VoiceIndicator
          isListening={stt.isListening}
          interimTranscript={stt.interimTranscript}
        />
      )}

      {/* Error indicators */}
      {(cameraError || modelError) && (
        <div
          style={{
            position: "absolute",
            bottom: 20,
            left: 20,
            color: "#f44",
            fontSize: "1rem",
            zIndex: 30,
          }}
        >
          {cameraError && <div>Camera: {cameraError}</div>}
          {modelError && <div>Model: {modelError}</div>}
        </div>
      )}

      {isModelLoading && (
        <div
          style={{
            position: "absolute",
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
            color: "#fff",
            fontSize: "1.5rem",
            zIndex: 30,
            pointerEvents: "none",
          }}
        >
          Loading gesture recognition...
        </div>
      )}
    </main>
  );
}

/* ── Recommendation sub-components (from main) ── */

function OutfitsView({
  greeting,
  styleAnalysis,
  outfits,
  activeIndex,
  onDotClick,
}: {
  greeting: string;
  styleAnalysis: string;
  outfits: Outfit[];
  activeIndex: number;
  onDotClick: (i: number) => void;
}) {
  const outfit = outfits[activeIndex];
  if (!outfit) return null;

  return (
    <div
      style={{
        width: "100%",
        display: "flex",
        flexDirection: "column",
        padding: 40,
        boxSizing: "border-box",
        color: "#fff",
      }}
    >
      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <p style={{ fontSize: 22, fontWeight: 300, margin: 0 }}>{greeting}</p>
        <p style={{ fontSize: 14, opacity: 0.6, marginTop: 6 }}>
          {styleAnalysis}
        </p>
      </div>

      {/* Outfit card */}
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          gap: 20,
        }}
      >
        <p
          style={{
            fontSize: 20,
            fontWeight: 600,
            letterSpacing: 1,
            margin: 0,
          }}
        >
          {outfit.outfit_name}
        </p>

        {/* Items row */}
        <div
          style={{
            display: "flex",
            gap: 24,
            justifyContent: "center",
            flexWrap: "wrap",
          }}
        >
          {outfit.items.map((oi, idx) => (
            <div
              key={idx}
              style={{
                textAlign: "center",
                width: 180,
              }}
            >
              <div
                style={{
                  width: 180,
                  height: 220,
                  background: "#1a1a1a",
                  borderRadius: 8,
                  overflow: "hidden",
                  marginBottom: 8,
                }}
              >
                <img
                  src={oi.item.cleaned_image_url ?? oi.item.flat_image_url ?? oi.item.image_url}
                  alt={oi.item.title}
                  style={{
                    width: "100%",
                    height: "100%",
                    objectFit: "contain",
                  }}
                />
              </div>
              <p
                style={{
                  fontSize: 13,
                  margin: 0,
                  opacity: 0.9,
                  whiteSpace: "nowrap",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                }}
              >
                {oi.item.title}
              </p>
              <p style={{ fontSize: 13, margin: "4px 0 0", opacity: 0.6 }}>
                {oi.item.price}
              </p>
            </div>
          ))}
        </div>

        {/* Mira comment */}
        <p
          style={{
            fontSize: 15,
            fontStyle: "italic",
            opacity: 0.7,
            maxWidth: 600,
            textAlign: "center",
            margin: 0,
          }}
        >
          &ldquo;{outfit.mira_comment}&rdquo;
        </p>
      </div>

      {/* Navigation dots */}
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          gap: 10,
          paddingTop: 20,
          pointerEvents: "auto",
        }}
      >
        {outfits.map((_, i) => (
          <button
            key={i}
            onClick={() => onDotClick(i)}
            style={{
              width: 10,
              height: 10,
              borderRadius: "50%",
              border: "none",
              background: i === activeIndex ? "#fff" : "rgba(255,255,255,0.3)",
              cursor: "pointer",
              padding: 0,
            }}
          />
        ))}
      </div>
    </div>
  );
}

