    89→    video: "/avatar/scripted/supportive_works.mp4",
    90→    emotion: "happy",
    91→    keywords: ["it works", "works", "actually works"],
    92→  },
    93→  "not bad at all": {
    94→    video: "/avatar/scripted/supportive_notbad.mp4",
    95→    emotion: "happy",
    96→    keywords: ["not bad", "pretty good", "decent"],
    97→  },
