   100→/**
   101→ * Find the best scripted response match for the given text.
   102→ *
   103→ * Pass 1: exact phrase `includes()` (case-insensitive).
   104→ * Pass 2: keyword scoring — longer keywords score higher. Threshold = 4.
   105→ */
   106→export function findScriptedResponse(text: string): ScriptedResponse | null {
   107→  const lower = text.toLowerCase();
   108→
   109→  // Pass 1 — exact phrase match
   110→  for (const [phrase, data] of Object.entries(SCRIPTED_RESPONSES)) {
   111→    if (lower.includes(phrase)) {
   112→      return { phrase, ...data };
   113→    }
   114→  }
   115→
   116→  // Pass 2 — keyword scoring
   117→  let bestMatch: ScriptedResponse | null = null;
   118→  let bestScore = 0;
   119→
   120→  for (const [phrase, data] of Object.entries(SCRIPTED_RESPONSES)) {
   121→    let score = 0;
   122→    for (const keyword of data.keywords) {
   123→      if (lower.includes(keyword)) {
   124→        score += keyword.length;
   125→      }
   126→    }
   127→    if (score > bestScore) {
   128→      bestScore = score;
   129→      bestMatch = { phrase, ...data };
   130→    }
   131→  }
   132→
   133→  return bestScore >= 4 ? bestMatch : null;
   134→}
   135→
   136→/**
   137→ * Regex-based fallback emotion detection when no scripted match.
   138→ * Used to pick a looping avatar state for the TTS path.
   139→ */
   140→export function detectEmotion(text: string): AvatarState {
   141→  const lower = text.toLowerCase();
   142→
   143→  if (/ew|gross|ugly|terrible|awful|yuck|no no|honey/.test(lower)) {
   144→    return "concerned";
   145→  }
   146→  if (/confused|what|why|huh|\?{2,}|don't understand/.test(lower)) {
   147→    return "thinking";
   148→  }
   149→  if (/love|amazing|perfect|yes!|gorgeous|stunning|beautiful|great/.test(lower)) {
   150→    return "excited";
   151→  }
   152→  if (/good|nice|works|not bad|decent|okay|fine/.test(lower)) {
   153→    return "happy";
   154→  }
   155→  if (/hmm|let me|thinking|consider/.test(lower)) {
   156→    return "thinking";
   157→  }
   158→
   159→  return "talking";
   160→}
