     1→/**
     2→ * Accumulates streaming text chunks and flushes complete sentences.
     3→ *
     4→ * Sentence boundaries are `.` `!` `?` followed by a space or end-of-input.
     5→ * Handles edge cases: decimal numbers ($29.99), ellipsis (...), empty chunks.
     6→ */
     7→export class SentenceBuffer {
     8→  private buffer = "";
     9→  private onSentence: (sentence: string) => void;
    10→
    11→  constructor(onSentence: (sentence: string) => void) {
    12→    this.onSentence = onSentence;
    13→  }
    14→
    15→  feed(chunk: string): void {
    16→    if (!chunk) return;
    17→    this.buffer += chunk;
    18→    this.drainSentences();
    19→  }
    20→
    21→  flush(): void {
    22→    const text = this.buffer.trim();
    23→    if (text) {
    24→      console.log("[SentenceBuffer] Flushing remainder:", text);
    25→      this.onSentence(text);
    26→    }
    27→    this.buffer = "";
    28→  }
    29→
    30→  private drainSentences(): void {
    31→    // Match sentence-ending punctuation followed by a space.
    32→    // Negative lookbehind avoids splitting on:
    33→    //   - decimal numbers: digit.digit (e.g. $29.99)
    34→    //   - ellipsis: two or more dots (e.g. "hmm...")
    35→    const sentenceEnd = /(?<!\d)(?<!\.)([.!?])\s/g;
    36→    let match: RegExpExecArray | null;
    37→    let lastIndex = 0;
    38→
    39→    while ((match = sentenceEnd.exec(this.buffer)) !== null) {
    40→      // Include the punctuation mark, not the trailing space
    41→      const sentence = this.buffer.slice(lastIndex, match.index + match[1].length).trim();
    42→      if (sentence) {
    43→        console.log("[SentenceBuffer] Sentence:", sentence);
    44→        this.onSentence(sentence);
    45→      }
    46→      lastIndex = match.index + match[0].length;
    47→    }
    48→
    49→    if (lastIndex > 0) {
    50→      this.buffer = this.buffer.slice(lastIndex);
    51→    }
    52→  }
    53→}
    54→

