     1→/**
     2→ * ElevenLabs TTS client — calls the backend proxy at /api/tts/speak.
     3→ *
     4→ * Falls back to browser SpeechSynthesis if the proxy is unavailable.
     5→ */
     6→
     7→export class ElevenLabsTTS {
     8→  private apiUrl: string;
     9→  private audio: HTMLAudioElement | null = null;
    10→  private speaking = false;
    11→
    12→  constructor(apiUrl: string) {
    13→    this.apiUrl = apiUrl;
    14→  }
    15→
    16→  async speak(
    17→    text: string,
    18→    onStart?: () => void,
    19→    onEnd?: () => void,
    20→  ): Promise<void> {
    21→    try {
    22→      console.log("[TTS] Sending to ElevenLabs:", text.slice(0, 100));
    23→      this.speaking = true;
    24→      onStart?.();
    25→
    26→      const resp = await fetch(`${this.apiUrl}/api/tts/speak`, {
    27→        method: "POST",
    28→        headers: { "Content-Type": "application/json" },
    29→        body: JSON.stringify({ text }),
    30→      });
    31→
    32→      if (!resp.ok) {
    33→        throw new Error(`TTS proxy error: ${resp.status}`);
    34→      }
    35→
    36→      const blob = await resp.blob();
    37→      const url = URL.createObjectURL(blob);
    38→
    39→      await new Promise<void>((resolve) => {
    40→        this.audio = new Audio(url);
    41→
    42→        this.audio.onended = () => {
    43→          console.log("[TTS] Playback finished:", text.slice(0, 60));
    44→          this.speaking = false;
    45→          URL.revokeObjectURL(url);
    46→          onEnd?.();
    47→          resolve();
    48→        };
    49→
    50→        this.audio.onerror = () => {
    51→          this.speaking = false;
    52→          URL.revokeObjectURL(url);
    53→          onEnd?.();
    54→          resolve();
    55→        };
    56→
    57→        this.audio.play().catch(() => {
    58→          this.speaking = false;
    59→          URL.revokeObjectURL(url);
    60→          onEnd?.();
    61→          resolve();
    62→        });
    63→      });
    64→    } catch (err) {
    65→      console.warn("[TTS] ElevenLabs proxy failed, falling back to browser TTS:", err);
    66→      this.speaking = false;
    67→
    68→      // Browser TTS fallback
    69→      await this.browserFallback(text, onStart, onEnd);
    70→    }
    71→  }
    72→
    73→  stop(): void {
    74→    if (this.audio) {
    75→      this.audio.pause();
    76→      this.audio = null;
    77→    }
    78→    this.speaking = false;
    79→    window.speechSynthesis?.cancel();
    80→  }
    81→
    82→  isSpeaking(): boolean {
    83→    return this.speaking;
    84→  }
    85→
    86→  private browserFallback(
    87→    text: string,
    88→    onStart?: () => void,
    89→    onEnd?: () => void,
    90→  ): Promise<void> {
    91→    return new Promise<void>((resolve) => {
    92→      if (!window.speechSynthesis) {
    93→        onEnd?.();
    94→        resolve();
    95→        return;
    96→      }
    97→
    98→      const utterance = new SpeechSynthesisUtterance(text);
    99→      utterance.rate = 1.0;
   100→      utterance.pitch = 1.1;
   101→
   102→      utterance.onstart = () => {
   103→        this.speaking = true;
   104→        onStart?.();
   105→      };
   106→
   107→      utterance.onend = () => {
   108→        this.speaking = false;
   109→        onEnd?.();
   110→        resolve();
   111→      };
   112→
   113→      utterance.onerror = () => {
   114→        this.speaking = false;
   115→        onEnd?.();
   116→        resolve();
   117→      };
   118→
   119→      window.speechSynthesis.speak(utterance);
   120→    });
   121→  }
   122→}
   123→

